  // ... state logic ...
  try {
    const result = await Promise.race([
      fn(),
      new Promise((_, reject) => 
        setTimeout(() => reject(new Error('Probe timeout')), timeoutMs ?? 5000)
      )
    ])
    this.onSuccess()
    return result
  } catch (err) {
    this.onFailure()
    throw err
  }
}
